import { ChatOpenAI } from "@langchain/openai";
import { getOpenAIBaseURL, OPENAI_KEY, OPENAI_MODEL } from "../config.ts";

let cached: ChatOpenAI | null = null;

export function getLLM(): ChatOpenAI {
  if (cached) return cached;
  cached = new ChatOpenAI({
    model: OPENAI_MODEL,
    apiKey: OPENAI_KEY,
    configuration: { baseURL: getOpenAIBaseURL() },
    temperature: 0.4,
    maxRetries: 2,
    timeout: 60000,
  });
  return cached;
}

export function trimContent(content: string, maxChars: number): string {
  if (content.length <= maxChars) return content;
  const head = content.slice(0, maxChars);
  return `${head}\n\n[... content truncated for brevity ...]`;
}

